1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  ActivityIndicator,
4	  Linking,
5	  Pressable,
6	  SafeAreaView,
7	  ScrollView,
8	  StyleSheet,
9	  Text,
10	  View,
11	} from 'react-native';
12	import { router, useLocalSearchParams } from 'expo-router';
13	import { Check, ChevronLeft, ExternalLink, X } from 'lucide-react-native';
14	import { ButtonPrimary } from '@/components/primitives/Button';
15	import { StatusPill } from '@/components/primitives/StatusPill';
16	import { useToast } from '@/components/primitives/Toast';
17	import { colors, radii, shadows, spacing } from '@/design/tokens';
18	import { textStyles } from '@/design/typography';
19	import { supabase } from '@/lib/supabase';
20	import type { Database } from '@/types/supabase';
21	
22	// US-040 — Campaign detail screen. Gated under the creator tab group so
23	// the shared TabBar stays visible; route matches the story AC
24	// (`app/(creator)/listing/[id].tsx`). Data flows through the
25	// get-listing-detail edge function (US-039) — that path is picked
26	// deliberately over direct PostgREST so it works around the current
27	// JWT-drift cascade that blocks gateway-verified table reads.
28	//
29	// Spec alignment (docs/design.md §4.2):
30	// - Back chevron header (lister handle deferred — requires a lister-profile
31	//   join the edge function does not yet expose; Spec gap noted in progress.txt).
32	// - Hero card with title, price, "Payout after approval" caption.
33	// - Sample videos rendered as tappable rows that open the URL in the
34	//   platform app via Linking.openURL — NOT embedded previews per the
35	//   design doc's "link-out only" v1 rule.
36	// - Eligibility rail: one row per PRE condition showing ✓/✗ plus the
37	//   required threshold and the creator's actual value (from the
38	//   edge-function `failed_conditions` additive `actual` field).
39	// - "What to film" post-condition bullet list (POST rows; not gated on
40	//   eligibility — reviewed at submission time, US-057+).
41	// - Sticky footer with the Apply CTA. Gate per §4.2:
42	//     eligible + !active-app  → ButtonPrimary "Apply to collab"
43	//     eligible + active-app   → StatusPill + disabled CTA
44	//     ineligible              → disabled CTA "Not eligible yet"
45	//     inactive listing        → no CTA, status banner at top
46	//
47	// Apply flow itself lands in US-041 (server-side re-check edge function)
48	// + US-042 (modal + toast). This screen's CTA currently surfaces a toast
49	// stub so the tap target is exercised during mobile-mcp verification.
50	
51	type ListingRow = Database['public']['Tables']['listings']['Row'];
52	type ConditionRow = Database['public']['Tables']['listing_conditions']['Row'];
53	type SampleVideoRow = Database['public']['Tables']['sample_videos']['Row'];
54	type Platform = Database['public']['Enums']['platform'];
55	type ListingStatus = Database['public']['Enums']['listing_status'];
56	
57	type FailedCondition = {
58	  metric: string;
59	  platform: Platform | null;
60	  required: number | boolean;
61	  actual: number | boolean | null;
62	};
63	
64	type DetailResponse = {
65	  listing: ListingRow;
66	  conditions: ConditionRow[];
67	  sample_videos: SampleVideoRow[];
68	  eligibility: {
69	    eligible: boolean;
70	    failed_conditions: FailedCondition[];
71	    has_active_application: boolean;
72	  };
73	};
74	
75	type LoadState =
76	  | { kind: 'loading' }
77	  | { kind: 'error'; code: 'not_found' | 'generic' }
78	  | { kind: 'ok'; data: DetailResponse };
79	
80	export default function ListingDetail() {
81	  const { id } = useLocalSearchParams<{ id: string }>();
82	  const { show: showToast } = useToast();
83	  const [state, setState] = useState<LoadState>({ kind: 'loading' });
84	
85	  const load = useCallback(async () => {
86	    if (!id) {
87	      setState({ kind: 'error', code: 'not_found' });
88	      return;
89	    }
90	    setState({ kind: 'loading' });
91	    const { data, error } = await supabase.functions.invoke<DetailResponse>(
92	      'get-listing-detail',
93	      { body: { listing_id: id } },
94	    );
95	    if (error) {
96	      const ctx = (error as { context?: unknown }).context;
97	      if (
98	        ctx &&
99	        typeof ctx === 'object' &&
100	        'status' in ctx &&
101	        typeof (ctx as { json?: unknown }).json === 'function'
102	      ) {
103	        const res = ctx as Response;
104	        if (res.status === 404) {
105	          setState({ kind: 'error', code: 'not_found' });
106	          return;
107	        }
108	      }
109	      console.error('get-listing-detail failed', error);
110	      setState({ kind: 'error', code: 'generic' });
111	      return;
112	    }
113	    if (!data) {
114	      setState({ kind: 'error', code: 'generic' });
115	      return;
116	    }
117	    setState({ kind: 'ok', data });
118	  }, [id]);
119	
120	  useEffect(() => {
121	    void load();
122	  }, [load]);
123	
124	  const onBack = useCallback(() => {
125	    // Slot-based layouts don't maintain a full stack, so fall back to
126	    // the feed when back is unavailable (Codebase Pattern #27/#95).
127	    if (router.canGoBack()) {
128	      router.back();
129	    } else {
130	      router.replace('/(creator)/feed');
131	    }
132	  }, []);
133	
134	  const onApply = useCallback(() => {
135	    showToast({
136	      message: 'Apply flow lands in US-042.',
137	      variant: 'success',
138	    });
139	  }, [showToast]);
140	
141	  return (
142	    <SafeAreaView style={styles.container}>
143	      <Header onBack={onBack} />
144	      {state.kind === 'loading' ? (
145	        <View style={styles.centered}>
146	          <ActivityIndicator color={colors.ink} />
147	        </View>
148	      ) : state.kind === 'error' ? (
149	        <ErrorBody code={state.code} onBack={onBack} />
150	      ) : (
151	        <DetailBody data={state.data} onApply={onApply} />
152	      )}
153	    </SafeAreaView>
154	  );
155	}
156	
157	function Header({ onBack }: { onBack: () => void }) {
158	  return (
159	    <View style={styles.header}>
160	      <Pressable
161	        onPress={onBack}
162	        hitSlop={spacing.md}
163	        accessibilityRole="button"
164	        accessibilityLabel="Back"
165	        testID="listing-back"
166	      >
167	        <ChevronLeft color={colors.ink} size={28} strokeWidth={2.5} />
168	      </Pressable>
169	      <Text style={[textStyles.h2, { color: colors.ink }]}>Campaign</Text>
170	      <View style={styles.headerSpacer} />
171	    </View>
172	  );
173	}
174	
175	function ErrorBody({
176	  code,
177	  onBack,
178	}: {
179	  code: 'not_found' | 'generic';
180	  onBack: () => void;
181	}) {
182	  const copy =
183	    code === 'not_found'
184	      ? 'This campaign is no longer available.'
185	      : 'Could not load this campaign. Try again in a moment.';
186	  return (
187	    <View style={styles.centered}>
188	      <Text style={[textStyles.h1, { color: colors.ink, textAlign: 'center' }]}>
189	        Campaign not found
190	      </Text>
191	      <Text
192	        style={[textStyles.body, { color: colors.ink70, textAlign: 'center', marginTop: spacing.sm }]}
193	      >
194	        {copy}
195	      </Text>
196	      <View style={{ marginTop: spacing.xl, minWidth: 160 }}>
197	        <ButtonPrimary label="Back to feed" onPress={onBack} testID="listing-error-back" />
198	      </View>
199	    </View>
200	  );
201	}
202	
203	function DetailBody({
204	  data,
205	  onApply,
206	}: {
207	  data: DetailResponse;
208	  onApply: () => void;
209	}) {
210	  const { listing, conditions, sample_videos, eligibility } = data;
211	
212	  const preConditions = useMemo(
213	    () => conditions.filter((c) => c.kind === 'pre'),
214	    [conditions],
215	  );
216	  const postConditions = useMemo(
217	    () => conditions.filter((c) => c.kind === 'post'),
218	    [conditions],
219	  );
220	
221	  const failureByKey = useMemo(() => {
222	    const map = new Map<string, FailedCondition>();
223	    for (const f of eligibility.failed_conditions) {
224	      map.set(conditionKey(f.metric, f.platform), f);
225	    }
226	    return map;
227	  }, [eligibility.failed_conditions]);
228	
229	  const inactiveBanner = getInactiveBanner(listing.status);
230	  const priceLabel = formatPrice(listing.price_cents, listing.currency);
231	
232	  return (
233	    <>
234	      <ScrollView
235	        contentContainerStyle={styles.scrollContent}
236	        showsVerticalScrollIndicator={false}
237	      >
238	        {inactiveBanner ? (
239	          <View style={styles.inactiveBanner} testID="listing-inactive-banner">
240	            <Text style={[textStyles.caption, { color: colors.ink }]}>
241	              {inactiveBanner}
242	            </Text>
243	          </View>
244	        ) : null}
245	
246	        <View style={styles.heroCard} testID="listing-hero">
247	          <Text style={[textStyles.display, { color: colors.ink }]}>
248	            {listing.title}
249	          </Text>
250	          <Text style={[textStyles.h1, styles.priceRow]} testID="listing-price">
251	            {priceLabel}
252	          </Text>
253	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
254	            Payout after approval
255	          </Text>
256	        </View>
257	
258	        {sample_videos.length > 0 ? (
259	          <Section title="Sample videos">
260	            <View style={styles.sampleList}>
261	              {sample_videos.map((v) => (
262	                <SampleVideoCell key={v.id} video={v} />
263	              ))}
264	            </View>
265	          </Section>
266	        ) : null}
267	
268	        {preConditions.length > 0 ? (
269	          <Section title="Eligibility">
270	            <View style={styles.eligibilityList}>
271	              {preConditions.map((c) => (
272	                <EligibilityRow
273	                  key={c.id}
274	                  condition={c}
275	                  failure={failureByKey.get(conditionKey(c.metric, c.platform)) ?? null}
276	                />
277	              ))}
278	            </View>
279	          </Section>
280	        ) : null}
281	
282	        {postConditions.length > 0 ? (
283	          <Section title="What to film">
284	            <View style={styles.bulletList}>
285	              {postConditions.map((c) => (
286	                <PostConditionRow key={c.id} condition={c} />
287	              ))}
288	            </View>
289	          </Section>
