    borderWidth: 2,
    borderRadius: radii.card,
    padding: spacing.base,
    ...shadows.hard,
  },
  heroCard: {
    backgroundColor: colors.surface,
    borderColor: colors.ink,
    borderWidth: 2,
    borderRadius: radii.card,
    padding: spacing.base,
    gap: spacing.xs,
    ...shadows.hard,
  },
  priceRow: {
    color: colors.cta,
    marginTop: spacing.sm,
  },
  section: {
    gap: spacing.md,
  },
  sampleList: {
    gap: spacing.md,
  },
  sampleRow: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: spacing.md,
    backgroundColor: colors.surface,
    borderColor: colors.ink,
    borderWidth: 2,
    borderRadius: radii.card,
    padding: spacing.base,
  },
  sampleText: {
    flex: 1,
    gap: spacing.xs,
  },
  eligibilityList: {
    gap: spacing.sm,
  },
  eligibilityRow: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: spacing.md,
    backgroundColor: colors.surface,
    borderColor: colors.ink,
    borderWidth: 2,
    borderRadius: radii.card,
    padding: spacing.md,
  },
  eligibilityIcon: {
    width: 28,
    height: 28,
    borderRadius: radii.pill,
    borderWidth: 2,
    alignItems: 'center',
    justifyContent: 'center',
  },
