1	import { useCallback } from 'react';
2	import { Pressable, SafeAreaView, StyleSheet, Text, View } from 'react-native';
3	import Animated, {
4	  useAnimatedStyle,
5	  useSharedValue,
6	  withSpring,
7	  type WithSpringConfig,
8	} from 'react-native-reanimated';
9	import * as Haptics from 'expo-haptics';
10	import { useRouter } from 'expo-router';
11	import { Building2, Video, type LucideIcon } from 'lucide-react-native';
12	import { colors, radii, shadows, spacing } from '@/design/tokens';
13	import { SPRING_SOFT, withReducedMotion } from '@/design/motion';
14	import { useReducedMotion } from '@/design/useReducedMotion';
15	import { textStyles } from '@/design/typography';
16	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
17	import { useAuth } from '@/lib/auth';
18	
19	// Role picker (docs/design.md §2.1 Welcome). Two large hard-shadow cards with
20	// 2px ink borders: "I'm a Creator" + "I'm a Company". Tapping routes forward
21	// to the role-specific signup screens that US-033/US-034 will flesh out.
22	// Press animation mirrors the CampaignCard pattern (Codebase Patterns #77,
23	// #78): animate shadowOpacity + translate on a single shared value; shadowOffset
24	// stays fixed because it isn't interpolatable through useAnimatedStyle.
25	export default function AuthIndex() {
26	  const router = useRouter();
27	
28	  const goCreator = useCallback(() => {
29	    router.push('/(auth)/signup/creator');
30	  }, [router]);
31	  const goLister = useCallback(() => {
32	    router.push('/(auth)/signup/lister');
33	  }, [router]);
34	
35	  return (
36	    <SafeAreaView style={styles.container}>
37	      <View style={styles.content}>
38	        <View style={styles.hero}>
39	          <Text style={[textStyles.display, styles.title]}>Marketify</Text>
40	          <Text style={[textStyles.body, styles.subtitle]}>
41	            Creators claim bounties. Companies post them. Pick your side.
42	          </Text>
43	        </View>
44	
45	        <View style={styles.cards}>
46	          <RolePickerCard
47	            icon={Video}
48	            title="I'm a Creator"
49	            body="Claim bounties and get paid for content you already make."
50	            accent={colors.primary}
51	            accentSoft={colors.primarySoft}
52	            onPress={goCreator}
53	            testID="auth-role-creator"
54	          />
55	          <RolePickerCard
56	            icon={Building2}
57	            title="I'm a Company"
58	            body="Post bounties and find creators who already fit your brief."
59	            accent={colors.cta}
60	            accentSoft={colors.warningSoft}
61	            onPress={goLister}
62	            testID="auth-role-lister"
63	          />
64	        </View>
65	
66	        {__DEV__ ? <DevRolePicker /> : null}
67	      </View>
68	    </SafeAreaView>
69	  );
70	}
71	
72	type RolePickerCardProps = {
73	  icon: LucideIcon;
74	  title: string;
75	  body: string;
76	  accent: string;
77	  accentSoft: string;
78	  onPress: () => void;
79	  testID?: string;
80	};
81	
82	function RolePickerCard({
83	  icon: Icon,
84	  title,
85	  body,
86	  accent,
87	  accentSoft,
88	  onPress,
89	  testID,
90	}: RolePickerCardProps) {
91	  const reduced = useReducedMotion();
92	  const pressed = useSharedValue(0);
93	
94	  const animatedStyle = useAnimatedStyle(() => {
95	    const v = pressed.value;
96	    return {
97	      transform: [
98	        { translateX: v * 3 },
99	        { translateY: v * 3 },
100	        { scale: 1 - v * 0.03 },
101	      ],
102	      shadowOpacity: 1 - v,
103	    };
104	  });
105	
106	  const handlePressIn = useCallback(() => {
107	    if (!onPress) return;
108	    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
109	    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
110	  }, [onPress, pressed, reduced]);
111	
112	  const handlePressOut = useCallback(() => {
113	    if (!onPress) return;
114	    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
115	  }, [onPress, pressed, reduced]);
116	
117	  return (
118	    <Pressable
119	      onPress={onPress}
120	      onPressIn={handlePressIn}
121	      onPressOut={handlePressOut}
122	      accessibilityRole="button"
123	      accessibilityLabel={title}
124	      accessibilityHint={body}
125	      testID={testID}
126	    >
127	      <Animated.View style={[styles.card, shadows.hard, animatedStyle]}>
128	        <View style={[styles.iconSquare, { backgroundColor: accentSoft, borderColor: accent }]}>
129	          <Icon size={32} strokeWidth={2.5} color={accent} />
130	        </View>
131	        <View style={styles.cardText}>
132	          <Text style={[textStyles.h1, styles.cardTitle]}>{title}</Text>
133	          <Text style={[textStyles.body, styles.cardBody]}>{body}</Text>
134	        </View>
135	      </Animated.View>
136	    </Pressable>
137	  );
138	}
139	
140	// Dev-only signin bypass. Skips the edge functions + routes directly into the
141	// role's tab group. Kept inside `__DEV__` so Metro strips the component (and
142	// the fake tokens / UUIDs it closes over) from production bundles — top-level
143	// const declarations would survive dead-code removal (Codebase Patterns #96).
144	function DevRolePicker() {
145	  const { signIn } = useAuth();
146	
147	  const creatorUser = {
148	    id: '00000000-0000-0000-0000-000000000001',
149	    username: 'dev_creator',
150	    email: null,
151	    role: 'creator' as const,
152	    created_at: new Date(0).toISOString(),
153	    updated_at: new Date(0).toISOString(),
154	    deleted_at: null,
155	  };
156	  const listerUser = {
157	    id: '00000000-0000-0000-0000-000000000002',
158	    username: 'dev_lister',
159	    email: 'dev-lister@example.com',
160	    role: 'lister' as const,
161	    created_at: new Date(0).toISOString(),
162	    updated_at: new Date(0).toISOString(),
163	    deleted_at: null,
164	  };
165	
166	  return (
167	    <View style={styles.devBlock}>
168	      <Text style={[textStyles.caption, styles.devCaption]}>DEV BYPASS</Text>
169	      <ButtonPrimary
170	        label="Sign in as creator"
171	        onPress={() => signIn('dev-creator-token', creatorUser)}
172	        accessibilityLabel="Dev sign in as creator"
173	        testID="dev-signin-creator"
174	      />
175	      <View style={styles.spacer} />
176	      <ButtonSecondary
177	        label="Sign in as lister"
178	        onPress={() => signIn('dev-lister-token', listerUser)}
179	        accessibilityLabel="Dev sign in as lister"
180	        testID="dev-signin-lister"
181	      />
182	    </View>
183	  );
184	}
185	
186	const styles = StyleSheet.create({
187	  container: {
188	    flex: 1,
189	    backgroundColor: colors.canvas,
190	  },
191	  content: {
192	    flex: 1,
193	    paddingHorizontal: spacing.base,
194	    paddingTop: spacing.xl,
195	    paddingBottom: spacing.base,
196	    gap: spacing.xl,
197	  },
198	  hero: {
199	    alignItems: 'center',
200	    gap: spacing.sm,
201	    paddingHorizontal: spacing.base,
202	  },
203	  title: {
204	    color: colors.ink,
205	    textAlign: 'center',
206	  },
207	  subtitle: {
208	    color: colors.ink70,
209	    textAlign: 'center',
210	  },
211	  cards: {
212	    gap: spacing.base,
213	  },
214	  card: {
215	    backgroundColor: colors.surface,
216	    borderRadius: radii.card,
217	    borderWidth: 2,
218	    borderColor: colors.ink,
219	    padding: spacing.lg,
220	    flexDirection: 'row',
221	    alignItems: 'center',
222	    gap: spacing.base,
223	  },
224	  iconSquare: {
225	    width: 64,
226	    height: 64,
227	    borderRadius: radii.card,
228	    borderWidth: 2,
229	    alignItems: 'center',
230	    justifyContent: 'center',
231	  },
232	  cardText: {
233	    flex: 1,
234	    gap: spacing.xs,
235	  },
236	  cardTitle: {
237	    color: colors.ink,
238	  },
239	  cardBody: {
240	    color: colors.ink70,
241	  },
242	  devBlock: {
243	    marginTop: 'auto',
244	    gap: spacing.sm,
245	    paddingTop: spacing.base,
246	    borderTopWidth: 1,
247	    borderTopColor: colors.hairline,
248	  },
249	  devCaption: {
250	    color: colors.ink40,
251	    textAlign: 'center',
252	    letterSpacing: 1,
253	  },
254	  spacer: {
255	    height: spacing.sm,
256	  },
257	});
